function DocsShell({ title, breadcrumbs = [], headings = [], showToc = true }, ...content) {
  const { div, h1, nav, span, button } = tags;
  const [navState, setNavState] = createSignal('expanded');
  const [mobileMenuOpen, setMobileMenuOpen] = createSignal(false);

  const toggleMobileMenu = () => setMobileMenuOpen(!mobileMenuOpen());

  const config = showToc && headings.length >= 3
    ? { regions: ['nav', 'body', 'aside'], grid: { areas: [['nav', 'body', 'aside']] }, nav: { width: '260px' }, aside: { width: '200px' } }
    : { regions: ['nav', 'body'], grid: { areas: [['nav', 'body']] }, nav: { width: '260px' } };

  return div({ class: css('_pt[56px] _minh[100vh]') },
    // Mobile menu bar (hidden on lg+)
    div({ class: css('_fixed _top[56px] _left0 _right0 _h[48px] _bgbg _borderB _flex _aic _px4 _z[50] _lg:none') },
      button({ class: css('_flex _aic _gap2 _px3 _py2 _r1 _bgmuted/30'), onclick: toggleMobileMenu },
        icon('menu', { size: '18px' }),
        span({ class: css('_textsm _fgmutedfg') }, 'Menu')
      )
    ),
    Shell({ config, navState, onNavStateChange: setNavState },
      Shell.Nav({ class: css('_bgbg _borderR _overflow[auto]') },
        // DocsSidebar component here
      ),
      Shell.Body({ class: css('_p6 _lg:p8 _maxw[800px] _lg:pt0 _pt[48px]') },
        // Breadcrumb and title
        nav({ class: css('_flex _aic _gap2 _textsm _fgmutedfg _mb4') },
          link({ href: '/docs' }, 'Docs'),
          ...breadcrumbs.map(b => [span('/'), link({ href: b.path }, b.label)]).flat()
        ),
        title && h1({ class: css('_heading2 _mb6') }, title),
        ...content
      ),
      showToc && headings.length >= 3 && Shell.Aside({ class: css('_bgbg _borderL _lg:flex _hidden') },
        // DocsToc component here
      )
    )
  );
}
